esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE redis_mem_fragmentation_ratio IS NOT NULL
    AND redis_used_memory IS NOT NULL
| STATS
    avg_frag = AVG(redis_mem_fragmentation_ratio),
    avg_used = AVG(redis_used_memory)
  BY redis, bdb, node, cluster
// Only evaluate shards with meaningful memory usage (>10 MB)
// Small shards naturally exhibit high fragmentation ratios
| WHERE avg_used > 10485760
// Alert when fragmentation ratio exceeds 1.5
// ratio = RSS / used_memory; values >> 1.0 indicate wasted memory
// Consider enabling active defragmentation or scheduling a restart
    AND avg_frag > 1.5
| SORT avg_frag DESC
